     1→import Foundation
     2→
     3→struct ImageItem: Equatable, Sendable {
     4→    let url: URL
     5→    let pdfPageIndex: Int?  // nil for regular images, 0-based for PDF pages
     6→
     7→    init(url: URL, pdfPageIndex: Int? = nil) {
     8→        self.url = url
     9→        self.pdfPageIndex = pdfPageIndex
    10→    }
    11→
    12→    var isPDF: Bool { pdfPageIndex != nil }
    13→
    14→    var fileName: String {
    15→        guard let page = pdfPageIndex else { return url.lastPathComponent }
    16→        return "\(url.lastPathComponent) — Page \(page + 1)"
    17→    }
    18→}
    19→
    20→// MARK: - Safe Array Subscript
    21→
    22→extension Collection {
    23→    subscript(safe index: Index) -> Element? {
    24→        indices.contains(index) ? self[index] : nil
    25→    }
    26→}
    27→

