     1→import Foundation
     2→import CoreGraphics
     3→import CoreServices
     4→import UniformTypeIdentifiers
     5→
     6→class ImageFolder {
     7→    private(set) var folderURL: URL
     8→    private(set) var images: [ImageItem] = []
     9→    var currentIndex: Int = 0
    10→
    11→    static let supportedTypes: Set<UTType> = [
    12→        .jpeg, .png, .tiff, .heic, .heif, .gif, .webP, .bmp, .pdf
    13→    ]
    14→
    15→    /// Check if a file URL is a supported image or PDF type
    16→    static func isSupported(url: URL) -> Bool {
    17→        guard let uttype = UTType(filenameExtension: url.pathExtension) else { return false }
    18→        return supportedTypes.contains { uttype.conforms(to: $0) }
    19→    }
    20→
    21→    init(containing fileURL: URL) {
    22→        self.folderURL = fileURL.deletingLastPathComponent()
    23→        self.images = scanFolder()
    24→
    25→        // 找到對應的 ImageItem (use .path — URL == can fail between constructed URLs and contentsOfDirectory)
    26→        let filePath = fileURL.resolvingSymlinksInPath().path
    27→        if let firstIndex = images.firstIndex(where: { $0.url.resolvingSymlinksInPath().path == filePath }) {
    28→            let firstItem = images[firstIndex]
    29→
    30→            if firstItem.isPDF {
    31→                // PDF 檔案：計算總頁數並恢復上次頁碼
    32→                let totalPages = images.filter { $0.url.resolvingSymlinksInPath().path == filePath }.count
    33→                let savedPage = Self.getLastViewedPage(for: fileURL, totalPages: totalPages)
    34→                self.currentIndex = firstIndex + savedPage
    35→            } else {
    36→                // 一般圖片
    37→                self.currentIndex = firstIndex
    38→            }
    39→        } else {
    40→            self.currentIndex = 0
    41→        }
    42→    }
    43→
    44→    /// Initialize from a folder URL directly (for drag-drop folder support).
    45→    /// Scans the folder and starts at the first image.
    46→    /// If the folder contains no images, searches up to 2 levels of subdirectories
    47→    /// for the first subfolder that does contain images.
    48→    init(folderURL: URL) {
    49→        self.folderURL = folderURL
    50→        self.images = scanFolder()
    51→
    52→        // Top-level empty: search subdirectories for the first folder with images
    53→        if images.isEmpty {
    54→            if let found = Self.findFirstSubfolderWithImages(in: folderURL, maxDepth: 2) {
    55→                self.folderURL = found
    56→                self.images = scanFolder()
    57→            }
    58→        }
    59→
    60→        self.currentIndex = 0
    61→    }
