   169→    /// 從 UserDefaults 讀取上次閱讀的 PDF 頁碼
   170→    private static func getLastViewedPage(for pdfURL: URL, totalPages: Int) -> Int {
   171→        let key = "pdf.lastPage.\(pdfURL.path)"
   172→        guard let savedPage = UserDefaults.standard.object(forKey: key) as? Int else {
   173→            return 0  // 預設第一頁
   174→        }
   175→        // 確保頁碼在有效範圍內（0 ~ totalPages-1）
   176→        return max(0, min(savedPage, totalPages - 1))
   177→    }
