     3→/// Limits concurrent thumbnail decoding to prevent CPU saturation during grid scrolling.
     4→/// Uses a priority queue: smaller priority value = higher urgency (closer to visible center).
     5→/// Equal priorities preserve FIFO insertion order via an explicit enqueue sequence.
     6→actor ThumbnailThrottle {
     7→    private struct Waiter {
     8→        let priority: Int
     9→        let sequence: Int
    10→        let continuation: CheckedContinuation<Void, Never>
    11→    }
    12→
    13→    private let maxConcurrent: Int
    14→    private var active = 0
    15→    private var waiters: [Waiter] = []
    16→    private var nextSequence = 0
    17→
    18→    init(maxConcurrent: Int = 4) {
    19→        self.maxConcurrent = maxConcurrent
    20→    }
    21→
    22→    /// Primary API: execute an operation with throttled concurrency.
    23→    /// Priority: smaller = higher priority (0 = highest, default for non-grid callers).
    24→    /// Grid callers pass distance-from-visible-center as priority.
    25→    /// Guarantees release via defer even if the task is cancelled.
    26→    func withThrottle<T: Sendable>(priority: Int = 0, _ operation: @Sendable () async -> T) async -> T {
    27→        let waitStart = CFAbsoluteTimeGetCurrent()
    28→        await acquire(priority: priority)
    29→        let waitMs = (CFAbsoluteTimeGetCurrent() - waitStart) * 1000
    30→        if waitMs > 1.0 {
    31→            GridPerfLog.log(String(format: "throttle: waited=%.2fms | pri=%d | active=%d | waiters=%d",
    32→                                   waitMs, priority, active, waiters.count))
    33→        }
    34→        defer { release() }
    35→        return await operation()
    36→    }
    37→
    38→    private func acquire(priority: Int) async {
    39→        if active < maxConcurrent {
    40→            active += 1
    41→            return
    42→        }
    43→        await withCheckedContinuation { (continuation: CheckedContinuation<Void, Never>) in
    44→            waiters.append(Waiter(priority: priority, sequence: nextSequence, continuation: continuation))
    45→            nextSequence += 1
    46→        }
    47→    }
    48→
    49→    private func release() {
    50→        active -= 1
    51→        guard !waiters.isEmpty else { return }
    52→        // Pick smallest priority first, then preserve enqueue order for ties.
    53→        let minIdx = waiters.indices.min { lhs, rhs in
    54→            let left = waiters[lhs]
    55→            let right = waiters[rhs]
    56→            if left.priority == right.priority {
    57→                return left.sequence < right.sequence
    58→            }
    59→            return left.priority < right.priority
    60→        }!
    61→        let next = waiters.remove(at: minIdx)
    62→        active += 1
    63→        next.continuation.resume()
    64→    }
    65→
    66→    // Test support
    67→    var activeCount: Int { active }
    68→    var waiterCount: Int { waiters.count }
    69→}
    70→

