   336→
   337→        let range: ClosedRange<Int>
   338→        switch prefetchDirection {
   339→        case .forward:
   340→            range = max(0, currentIndex - cacheRadius)...min(items.count - 1, currentIndex + cacheRadius + prefetchExtra)
   341→        case .backward:
   342→            range = max(0, currentIndex - cacheRadius - prefetchExtra)...min(items.count - 1, currentIndex + cacheRadius)
   343→        case .none:
   344→            range = max(0, currentIndex - cacheRadius)...min(items.count - 1, currentIndex + cacheRadius)
   345→        }
   346→
