   348→        let activeImageURLs = Set(items[range].filter { !$0.isPDF }.map(\.url))
   349→        let activePDFKeys = Set(items[range].compactMap { item in
   350→            item.pdfPageIndex.map { PDFCacheKey(url: item.url, pageIndex: $0) }
   351→        })
   352→        let activePDFURLs = Set(items[range].filter { $0.isPDF }.map(\.url))
   353→
   354→        // 取消不在範圍內的預載任務
   355→        for (url, task) in imagePrefetchTasks where !activeImageURLs.contains(url) {
   356→            task.cancel()
