    44→    /// Initialize from a folder URL directly (for drag-drop folder support).
    45→    /// Scans the folder and starts at the first image.
    46→    /// If the folder contains no images, searches up to 2 levels of subdirectories
    47→    /// for the first subfolder that does contain images.
    48→    init(folderURL: URL) {
    49→        self.folderURL = folderURL
    50→        self.images = scanFolder()
    51→
    52→        // Top-level empty: search subdirectories for the first folder with images
    53→        if images.isEmpty {
    54→            if let found = Self.findFirstSubfolderWithImages(in: folderURL, maxDepth: 2) {
    55→                self.folderURL = found
    56→                self.images = scanFolder()
    57→            }
    58→        }
    59→
    60→        self.currentIndex = 0
    61→    }
    62→
    63→    private func scanFolder() -> [ImageItem] {
    64→        let fm = FileManager.default
    65→        guard let contents = try? fm.contentsOfDirectory(
    66→            at: folderURL,
    67→            includingPropertiesForKeys: [.contentTypeKey],
    68→            options: .skipsHiddenFiles
    69→        ) else { return [] }
    70→
    71→        // Single pass: filter supported files and capture their UTType
    72→        let supported: [(url: URL, type: UTType)] = contents.compactMap { url in
    73→            guard let type = try? url.resourceValues(forKeys: [.contentTypeKey]).contentType,
    74→                  Self.supportedTypes.contains(where: { type.conforms(to: $0) })
    75→            else { return nil }
    76→            return (url, type)
    77→        }
    78→        .sorted { $0.url.lastPathComponent.localizedStandardCompare($1.url.lastPathComponent) == .orderedAscending }
    79→
    80→        // Expand PDFs into per-page items
    81→        return supported.flatMap { (url, type) -> [ImageItem] in
    82→            if type.conforms(to: .pdf) {
    83→                let count = Self.pdfPageCount(for: url)
    84→                guard count > 0 else { return [] }
    85→                return (0..<count).map { ImageItem(url: url, pdfPageIndex: $0) }
    86→            } else {
    87→                return [ImageItem(url: url)]
    88→            }
    89→        }
    90→    }
    91→
    92→    // MARK: - Subfolder Discovery
    93→
    94→    /// BFS search for the first subdirectory that contains supported images.
    95→    /// - Parameters:
    96→    ///   - rootURL: The folder to start searching from (its direct children are depth 1).
    97→    ///   - maxDepth: Maximum depth to search (e.g. 2 means grandchildren at most).
    98→    /// - Returns: The URL of the first subfolder containing images, or nil.
    99→    static func findFirstSubfolderWithImages(in rootURL: URL, maxDepth: Int) -> URL? {
   100→        let fm = FileManager.default
   101→        var queue: [(url: URL, depth: Int)] = []
   102→
   103→        // Seed queue with immediate subdirectories (depth 1)
   104→        let (_, rootSubdirs) = scanFolderContents(rootURL, using: fm)
   105→        for child in rootSubdirs {
   106→            queue.append((child, 1))
   107→        }
   108→
   109→        while !queue.isEmpty {
   110→            let (currentURL, depth) = queue.removeFirst()
   111→
   112→            let (hasImages, subdirs) = scanFolderContents(currentURL, using: fm)
   113→            if hasImages {
   114→                return currentURL
   115→            }
   116→
   117→            // Enqueue deeper subdirectories if within depth limit
   118→            if depth < maxDepth {
   119→                for child in subdirs {
   120→                    queue.append((child, depth + 1))
   121→                }
   122→            }
   123→        }
   124→
   125→        return nil
   126→    }
   127→
   128→    /// Single-pass scan: checks for supported images AND collects sorted subdirectories.
   129→    /// Reads directory contents once with all needed resource keys to avoid redundant I/O.
   130→    private static func scanFolderContents(_ url: URL, using fm: FileManager) -> (hasImages: Bool, subdirs: [URL]) {
   131→        guard let contents = try? fm.contentsOfDirectory(
   132→            at: url,
   133→            includingPropertiesForKeys: [.isDirectoryKey, .isPackageKey, .contentTypeKey],
   134→            options: .skipsHiddenFiles
   135→        ) else { return (false, []) }
   136→
   137→        var subdirs: [URL] = []
   138→
   139→        for child in contents {
   140→            guard let values = try? child.resourceValues(
   141→                forKeys: [.isDirectoryKey, .isPackageKey, .contentTypeKey]
   142→            ) else { continue }
   143→
   144→            if values.isDirectory == true && values.isPackage != true {
   145→                subdirs.append(child)
   146→            } else if let type = values.contentType,
   147→                      supportedTypes.contains(where: { type.conforms(to: $0) }) {
