            try minimalPNG().write(to: url)
        }

        let folder = ImageFolder(folderURL: tempDir)
        contentView.configure(with: folder, imageLoader: loader)

        // Wait for async initialization
        try await Task.sleep(nanoseconds: 100_000_000) // 100ms

        // Test passes if it doesn't crash and layout completes
        XCTAssertNotNil(contentView)
    }

    // MARK: - Layout Helpers tests (Implicit)
    func testLayoutCalculations() {
        // ContinuousScrollContentView logic uses unflipped system (y=0 at bottom)
        // With imageSizes: [800x600, 800x600] and containerWidth 800
        // Scaled height is 600.
        // Array of offsets should be [totalHeight - 600, totalHeight - 1200]

        // As recalculateLayout is private, test functionality implicitly through public functions
        // if they were available, but currently CalculateCurrentIndex needs imageSizes which are private.
        // We ensure standard init doesn't throw.
    }

    // MARK: - View Recycling Tests

    func testCalculateVisibleRange_withBuffer_returnsCorrectRange() async throws {
        // Given: Configure with 10 images, each 1000px tall with 800px container width
        let tempDir = FileManager.default.temporaryDirectory.appendingPathComponent(UUID().uuidString)
        try FileManager.default.createDirectory(at: tempDir, withIntermediateDirectories: true)
        defer { try? FileManager.default.removeItem(at: tempDir) }

        for i in 0..<10 {
            let url = tempDir.appendingPathComponent("img\(i).png")
            try createPNG(width: 800, height: 1000).write(to: url)
        }

        let folder = ImageFolder(folderURL: tempDir)
        contentView.configure(with: folder, imageLoader: loader)
        contentView.containerWidth = 800

        // Wait for preload
        try await Task.sleep(nanoseconds: 200_000_000)

        // When: Scroll to image 3 (y = 2000-3000)
        let visibleRect = NSRect(x: 0, y: 2000, width: 800, height: 800)

        // Then: calculateVisibleRange should return range including buffer
        // Visible: images 2-3, with buffer 2: should be 0-5
        let range = contentView.calculateVisibleRange(for: visibleRect)

        XCTAssertGreaterThanOrEqual(range.lowerBound, 0, "Lower bound should be >= 0")
        XCTAssertLessThanOrEqual(range.upperBound, 5, "Upper bound should be <= 5 with buffer")
    }

    func testCalculateVisibleRange_emptyImageSizes_returnsZeroRange() {
        // Given: Empty contentView with no images
        let visibleRect = NSRect(x: 0, y: 0, width: 800, height: 800)

        // When
        let range = contentView.calculateVisibleRange(for: visibleRect)

        // Then: Should return 0...0 for empty state
        XCTAssertEqual(range, 0...0, "Empty imageSizes should return 0...0")
    }

    func testFrameForImage_returnsCorrectFrame() async throws {
        // Given
        let tempDir = FileManager.default.temporaryDirectory.appendingPathComponent(UUID().uuidString)
        try FileManager.default.createDirectory(at: tempDir, withIntermediateDirectories: true)
        defer { try? FileManager.default.removeItem(at: tempDir) }

        // Create 2 images: 800x600 and 800x1200
        try createPNG(width: 800, height: 600).write(to: tempDir.appendingPathComponent("img0.png"))
        try createPNG(width: 800, height: 1200).write(to: tempDir.appendingPathComponent("img1.png"))

        let folder = ImageFolder(folderURL: tempDir)
        contentView.configure(with: folder, imageLoader: loader)
        contentView.containerWidth = 800

        // Wait for preload
        try await Task.sleep(nanoseconds: 200_000_000)

        // When: Get frame for second image
        let frame1 = contentView.frameForImage(at: 1)

        // Then: Second image should be at y=0 (bottom) with height 1200
        XCTAssertEqual(frame1.width, 800, accuracy: 0.1)
        XCTAssertEqual(frame1.height, 1200, accuracy: 0.1)
        XCTAssertEqual(frame1.origin.y, 0, accuracy: 0.1, "Second image should be at bottom")

        // And: First image should be above second
        let frame0 = contentView.frameForImage(at: 0)
        XCTAssertEqual(frame0.width, 800, accuracy: 0.1)
        XCTAssertEqual(frame0.height, 600, accuracy: 0.1)
        XCTAssertEqual(frame0.origin.y, 1200, accuracy: 0.1, "First image should be above second")
    }

    // MARK: - Index Tracking Tests

    func testCalculateCurrentIndex_returnsCorrectIndex() async throws {
        // Given
        let tempDir = FileManager.default.temporaryDirectory.appendingPathComponent(UUID().uuidString)
        try FileManager.default.createDirectory(at: tempDir, withIntermediateDirectories: true)
        defer { try? FileManager.default.removeItem(at: tempDir) }

        // Create 3 images, each 800x1000
        for i in 0..<3 {
            try createPNG(width: 800, height: 1000).write(to: tempDir.appendingPathComponent("img\(i).png"))
        }

        let folder = ImageFolder(folderURL: tempDir)
        contentView.configure(with: folder, imageLoader: loader)
        contentView.containerWidth = 800

        // Wait for preload
        try await Task.sleep(nanoseconds: 200_000_000)

        // When/Then: Test various scroll positions
        // Total height = 3000, images at: [2000-3000], [1000-2000], [0-1000]

        // At y=2500 (middle of image 0)
        XCTAssertEqual(contentView.calculateCurrentIndex(for: 2500), 0, "Should return index 0")

        // At y=1500 (middle of image 1)
        XCTAssertEqual(contentView.calculateCurrentIndex(for: 1500), 1, "Should return index 1")

        // At y=500 (middle of image 2)
        XCTAssertEqual(contentView.calculateCurrentIndex(for: 500), 2, "Should return index 2")
    }
}

